// Normalize incoming form data
const input = $input.first().json.body;

// Normalize phone to E.164
let phone = (input.phone || '').replace(/[^\d+]/g, '');
if (phone && !phone.startsWith('+')) {
  if (phone.length === 10) phone = '+1' + phone;
  else if (phone.length === 11 && phone.startsWith('1')) phone = '+' + phone;
}

// Validate required fields
const errors = [];
if (!input.first_name || !input.first_name.trim()) errors.push('first_name is required');
if (!input.email || !input.email.trim()) errors.push('email is required');
if (!phone) errors.push('phone is required');

const leadId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r = Math.random() * 16 | 0; return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16); });
const assignedAt = new Date().toISOString();

return [{
  json: {
    lead_id: leadId,
    first_name: (input.first_name || '').trim(),
    last_name: (input.last_name || '').trim(),
    phone: phone || null,
    email: (input.email || '').trim().toLowerCase(),
    source: 'website_form',
    vehicle_interest: (input.vehicle_interest || '').trim() || null,
    message: (input.message || '').trim() || null,
    company_id: input.company_id || null,
    stage: 'new',
    intent_score: 'cold',
    sequence_step: 0,
    demo_mode: true,
    opted_out: false,
    salesperson_alerted: false,
    sms_count: 0,
    autopilot_active: false,
    assigned_at: assignedAt,
    rep_response_at: null,
    assigned_to: null,
    _validation_errors: errors
  }
}];

const lead = $('Normalize Form Data').first().json;
const duplicates = $input.first().json;
const results = Array.isArray(duplicates) ? duplicates : [duplicates];
const isDuplicate = results.length > 0 && results[0]?.id;

if (isDuplicate) {
  return [{ json: { ...lead, _is_duplicate: true, _existing_id: results[0].id } }];
}
return [{ json: { ...lead, _is_duplicate: false } }];

// Shift-aware round-robin assignment
const baseUrl = $env.SUPABASE_URL;
const key = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = {
  'apikey': key,
  'Authorization': `Bearer ${key}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

function getMinutesInTimeZone(date, timeZone) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
    timeZone: timeZone || 'America/Toronto'
  }).formatToParts(date);

  const hours = parseInt(parts.find(part => part.type === 'hour')?.value || '0', 10);
  const minutes = parseInt(parts.find(part => part.type === 'minute')?.value || '0', 10);
  return hours * 60 + minutes;
}

function isWorking(rep, date) {
  if (!rep?.active) return false;
  const start = Number(rep.shift_start_minutes);
  const end = Number(rep.shift_end_minutes);
  if (!Number.isFinite(start) || !Number.isFinite(end) || start === end) return true;

  const nowMinutes = getMinutesInTimeZone(date, rep.shift_timezone || 'America/Toronto');
  if (start < end) {
    return nowMinutes >= start && nowMinutes < end;
  }

  return nowMinutes >= start || nowMinutes < end;
}

const repsRes = await fetch(`${baseUrl}/rest/v1/profiles?active=eq.true&select=id,name,rr_order,active,shift_start_minutes,shift_end_minutes,shift_timezone`, { headers });
const repsRaw = await repsRes.json();
const now = new Date();
const reps = (Array.isArray(repsRaw) ? repsRaw : [])
  .filter(rep => isWorking(rep, now))
  .sort((a, b) => {
    const orderDiff = (a.rr_order ?? 0) - (b.rr_order ?? 0);
    if (orderDiff !== 0) return orderDiff;
    return (a.name || '').localeCompare(b.name || '');
  });

if (reps.length === 0) {
  return [{ json: { ...$input.first().json, assigned_to: null, autopilot_active: true } }];
}

const settingsRes = await fetch(`${baseUrl}/rest/v1/settings?key=eq.rr_index&select=value`, { headers });
const settings = await settingsRes.json();
const rawIndex = settings[0]?.value ?? 0;
const currentIndex = typeof rawIndex === 'number' ? rawIndex : parseInt(String(rawIndex).replace(/[^\d-]/g, ''), 10) || 0;
const idx = ((currentIndex % reps.length) + reps.length) % reps.length;
const assignedRep = reps[idx];
const nextIndex = (idx + 1) % reps.length;

await fetch(`${baseUrl}/rest/v1/settings?key=eq.rr_index`, {
  method: 'PATCH',
  headers: { ...headers, 'Prefer': 'return=minimal' },
  body: JSON.stringify({ value: nextIndex })
});

return [{ json: { ...$input.first().json, assigned_to: assignedRep.id, autopilot_active: false } }];

const lead = $('Round Robin Assign').first().json;
const inventoryRaw = $input.first().json;
const inventory = Array.isArray(inventoryRaw) ? inventoryRaw : [inventoryRaw];

const inventoryList = inventory
  .filter(v => v && v.vehicle)
  .map(v => `- ${v.vehicle} | ${v.color || 'N/A'} | ${Number(v.mileage || 0).toLocaleString()} km | $${Number(v.price || 0).toLocaleString()}`)
  .join('\n');

const dealerName = $env.DEALERSHIP_NAME || 'Style Auto';
const dealerCity = $env.DEALERSHIP_CITY || 'Quebec';
const dealerHours = $env.DEALERSHIP_HOURS || 'Mon-Fri 9am-6pm, Sat 10am-4pm';
const salespersonName = $env.SALESPERSON_NAME || 'our sales team';
const salespersonPhone = $env.SALESPERSON_PHONE || '';

const systemPrompt = `You are the friendly, professional email assistant for ${dealerName}, a car dealership in ${dealerCity}.
Hours: ${dealerHours}
Salesperson: ${salespersonName}${salespersonPhone ? ' (' + salespersonPhone + ')' : ''}

Current available inventory:
${inventoryList || '(No inventory loaded yet)'}

Your job:
- Write a warm, personalized welcome email to a new lead who just submitted an inquiry form
- If they mentioned a specific vehicle, reference it and include relevant inventory details
- If the vehicle they want is available, highlight it; if not, suggest similar options from inventory
- Keep the tone conversational, warm, and professional — not robotic or salesy
- End with a clear next step (e.g., "Reply to this email or call us at...")
- Do NOT use placeholder brackets like [Name] — use the actual lead data provided

Respond with ONLY a JSON object (no markdown, no code fences):
{"subject": "email subject line", "html": "<html email body with basic formatting>", "text": "plain text version"}`;

const userPrompt = `New lead inquiry:
- Name: ${lead.first_name}${lead.last_name ? ' ' + lead.last_name : ''}
- Email: ${lead.email}
- Phone: ${lead.phone || 'not provided'}
- Vehicle interest: ${lead.vehicle_interest || 'general inquiry'}
- Message: ${lead.message || '(none)'}

Write the welcome email.`;

return [{ json: { system_prompt: systemPrompt, user_prompt: userPrompt, lead } }];

const response = $input.first().json;
const lead = $('Build Email Prompt').first().json.lead;

let emailData;
try {
  const content = response.content?.[0]?.text || '';
  // Strip any code fences if Claude wraps them
  const cleaned = content.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  emailData = JSON.parse(cleaned);
} catch (e) {
  // Fallback template if Claude response can't be parsed
  const dealerName = $env.DEALERSHIP_NAME || 'Style Auto';
  emailData = {
    subject: `Thanks for your inquiry, ${lead.first_name}!`,
    html: `<p>Hi ${lead.first_name},</p><p>Thank you for reaching out to ${dealerName}! We received your inquiry${lead.vehicle_interest ? ' about the ' + lead.vehicle_interest : ''} and will get back to you shortly.</p><p>Best regards,<br/>${dealerName} Team</p>`,
    text: `Hi ${lead.first_name}, thank you for reaching out to ${dealerName}! We received your inquiry${lead.vehicle_interest ? ' about the ' + lead.vehicle_interest : ''} and will get back to you shortly.`
  };
}

return [{ json: { ...emailData, lead_id: lead.lead_id, lead_email: lead.email, lead_first_name: lead.first_name, company_id: lead.company_id, demo_mode: lead.demo_mode } }];

// Demo mode — skip Resend but pass data through
const data = $input.first().json;
console.log('[DEMO] Would have sent email to:', data.lead_email);
console.log('[DEMO] Subject:', data.subject);
return [{ json: { ...data, _email_sent: false, _demo_skipped: true } }];

// Merge paths — pick up lead_id from either Resend response or demo skip
const data = $input.first().json;
const parsedData = $('Parse Claude Response').first().json;

// Get the actual Supabase lead UUID (from the insert response)
const insertedLead = $('Insert Lead to Supabase').first().json;
const leadUuid = Array.isArray(insertedLead) ? insertedLead[0].id : insertedLead.id;

return [{ json: { lead_id: leadUuid, company_id: parsedData.company_id, subject: parsedData.subject, email_sent: !data._demo_skipped, resend_id: data.id || null } }];
